export default {
components: { NavBar },
  // ... existing code ...
  getHealthData() {
    return uni.getStorageSync('healthData') || {
      steps: 0,
      calories: 0,
      sleep: 0,
      water: 0,
      weight: null,
      bloodPressure: null,
      bloodSugar: null,  // 血糖
      heartRate: null    // 心率
    };
  },
  updateBloodSugar(level) {
    const data = this.getHealthData();
    data.bloodSugar = `${level} mmol/L`;
    uni.setStorageSync('healthData', data);
  },
  updateHeartRate(bpm) {
    const data = this.getHealthData();
    data.heartRate = `${bpm} bpm`;
    uni.setStorageSync('healthData', data);
  },
  updateSteps(count) {
  const data = this.getHealthData();
  data.steps = count;
  uni.setStorageSync('healthData', data);
}
}